export function matchCareers(scores: Scores): { career: Career; match: number }[] {
  return CAREERS.map((career) => {
    let distance = 0;
    let maxDistance = 0;
    for (const trait of TRAITS) {
      distance += Math.abs(scores[trait] - career.profile[trait]);
      maxDistance += 100;
    }
    const match = Math.round((1 - distance / maxDistance) * 100);
    return { career, match: Math.max(0, Math.min(100, match)) };
  }).sort((a, b) => b.match - a.match);
}

export function toScores(counts: Scores): Scores {
  const total = TRAITS.reduce((sum, t) => sum + counts[t], 0) || 1;
  return {
    Analytical: Math.round((counts.Analytical / total) * 100),
    Creative: Math.round((counts.Creative / total) * 100),
    Social: Math.round((counts.Social / total) * 100),
    Risk: Math.round((counts.Risk / total) * 100),
  };
}

const BACHELOR_ALIASES: Record<string, string[]> = {
  "Any Design BSc": ["Any Design BSc"],
};

export function bachelorMatches(careerBachelor: string, selected: string): boolean {
  if (selected === "Any Design BSc") return true;
  const terms = BACHELOR_ALIASES[selected] ?? [selected];
  return terms.some((t) => careerBachelor.includes(t));
}

const MASTER_ALIASES: Record<string, string[]> = {
  "Product Service System Design (PSSD)": ["PSSD", "Product Service System Design"],
};

export function masterMatches(careerMaster: string, selected: string): boolean {
  if (selected === "Any Design MSc") return true;
  const terms = MASTER_ALIASES[selected] ?? [selected];
  return terms.some((t) => careerMaster.includes(t));
}

export function getCareersByDegree(bachelor: string, master: string): Career[] {
  return CAREERS.filter((c) => {
    const bMatch = !bachelor || bachelorMatches(c.bachelor, bachelor);
    const mMatch = !master || masterMatches(c.master, master);
    return bMatch && mMatch;
  });
}
